package com.google.gson;
import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.Gson;
import com.google.gson.JsonElement;
import com.google.gson.JsonNull;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

import java.lang.reflect.Method;

public class GsonToJsonTreeTest {

    private Gson gson;

    @BeforeEach
    public void setUp() {
        gson = new Gson();
    }

    @Test
    public void testToJsonTree_NullInput_ReturnsJsonNullInstance() {
        JsonElement result = gson.toJsonTree(null);
        assertSame(JsonNull.INSTANCE, result);
    }

    @Test
    public void testToJsonTree_NonNullInput_UsesClassType() throws Exception {
        String input = "testString";

        // Use reflection to get the private toJsonTree(Object, Type) method
        Method toJsonTreeWithTypeMethod = Gson.class.getDeclaredMethod("toJsonTree", Object.class, java.lang.reflect.Type.class);
        toJsonTreeWithTypeMethod.setAccessible(true);

        // Call the public toJsonTree(Object) method
        JsonElement resultPublic = gson.toJsonTree(input);

        // Call the private toJsonTree(Object, Type) method directly with same input and type
        JsonElement resultPrivate = (JsonElement) toJsonTreeWithTypeMethod.invoke(gson, input, input.getClass());

        // The results should be equal
        assertEquals(resultPrivate, resultPublic);
        assertNotNull(resultPublic);
    }
}
